import React from 'react';

function Toolbox({ data }) {
  if (!data || data.length === 0) return null;

  return (
    <section id="toolbox" className="py-8 md:py-12 bg-white">
      <div className="max-w-7xl mx-auto px-4">
        <p className="text-xs uppercase tracking-widest text-gray-500 font-semibold mb-4">
          Working System
        </p>
        <h2 className="text-4xl md:text-5xl font-black text-gray-900 mb-8">Toolbox</h2>

        <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-7 gap-3 md:gap-4">
          {data.map((tool) => (
            <div
              key={tool.id}
              className="flex flex-col items-center text-center group cursor-pointer p-3 rounded-lg border border-gray-200 hover:border-gray-400 hover:bg-gray-50 transition-all duration-300"
            >
              {/* Tool Icon */}
              <div className="w-14 h-14 md:w-16 md:h-16 flex items-center justify-center mb-3 overflow-hidden">
                {tool.image ? (
                  <img
                    src={tool.image}
                    alt={tool.name}
                    className="w-full h-full object-contain"
                  />
                ) : (
                  <span className="text-3xl font-bold text-gray-900">{tool.icon}</span>
                )}
              </div>
              
              {/* Tool Name */}
              <p className="text-xs md:text-sm font-semibold text-gray-900 group-hover:text-gray-600 transition-colors">
                {tool.name}
              </p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

export default Toolbox;
